INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 106001, "たまには\n協力するのもいいんじゃない？\nあたしも手を貸してあげる", 0, 7, "キャル", -363.0, 0, 0.0, 7001, 1, 1, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 105901, "多くの方と協力して\n戦えるようです\n主さまなら、さぞ\nご活躍なさることでしょう", 0, 7, "コッコロ", -363.0, 0, 0.0, 7002, 1, 1, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 105801, "たくさんの人と一緒に\n協力バトルです！\nがんばりましょう☆", 0, 7, "ペコリーヌ", -363.0, 0, 0.0, 7003, 1, 1, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 105801, "ジュエルを食べ物…\nいえ、貴重品と交換できます！", 0, 10, "ペコリーヌ", -363.0, 0, 0.0, 10001, 1, 1, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 106001, "ジュエルはよく考えて\n使うことね\n無駄遣い厳禁！", 0, 10, "キャル", -363.0, 0, 0.0, 10002, 1, 1, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 105901, "主さまのジュエルで\n貴重な品々を購入できます\nですが、無駄遣いは\n『めっ』でございますよ", 0, 10, "コッコロ", -363.0, 0, 0.0, 10003, 1, 1, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 106401, "ジュエルがあれば\n貴重品と交換できるみたい\n大事に使いましょうね", 0, 10, "シェフィ", -363.0, 2104010, 0.0, 10004, 1, 1, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 2);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 105801, "特定の条件を達成すると\n報酬がもらえますよ！\nがんばりましょう♪　", 0, 12, "ペコリーヌ", -416.5, 0, 0.0, 12001, 1, 1, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 106001, "思い出が詰まってるって\nいろいろあったけど\n振り返るのもいいんじゃない？", 0, 13, "キャル", -363.0, 0, 0.0, 13001, 1, 1, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 105901, "主さまとの楽しい日々…\nこちらで何度でも\n思い返しましょう♪", 0, 13, "コッコロ", -363.0, 0, 0.0, 13002, 1, 1, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 106401, "みんなとの大切な思い出が\nたくさん詰まってるのね\n一緒に振り返って、\n心に刻みたいわ", 0, 13, "シェフィ", -363.0, 2104010, 0.0, 13003, 1, 1, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 2);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 105801, "女の子との思い出が\nたくさん見られますよ！\nヒューヒュー♪\nモテモテですねー☆", 0, 13, "ペコリーヌ", -363.0, 0, 0.0, 13004, 1, 1, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 105901, "育成に必要なアイテムが\n獲得できるクエストです\nわたくし、主さまのために、\n強くなりますよ", 0, 14, "コッコロ", -363.0, 0, 0.0, 14001, 1, 1, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 106401, "このクエストを攻略すると、\nアイテムが手に入るらしいわ。\nもっと強くなるために、\n一生懸命がんばるわね！", 0, 14, "シェフィ", -363.0, 2104010, 0.0, 14002, 1, 1, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 2);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 105801, "このクエストを攻略すれば、\nアイテムがもらえますよ\nたくさん集めて、どんどん\n強くなっちゃいましょう！", 0, 14, "ペコリーヌ", -363.0, 0, 0.0, 14003, 1, 1, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 106001, "クエストを攻略すると、\nアイテムが手に入るんだって\nもらえるものは、\nもらっておきましょ！", 0, 14, "キャル", -363.0, 0, 0.0, 14004, 1, 1, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 105901, "主さま、旅の準備を整えて\nより充実した冒険をいたし\nましょう", 0, 15, "コッコロ", -470.0, 0, 0.0, 15001, 1, 1, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 106401, "ねぇ…クランに加入してみない？\n一人も楽しいけど、みんなと\n一緒も賑やかでいいと思うの", 0, 16, "シェフィ", -363.0, 2104010, 0.0, 16001, 1, 1, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 2);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 105801, "クランに加入してみませんか？\nみんなといっしょに冒険した方が、\n楽しいですよ！", 0, 16, "ペコリーヌ", -363.0, 0, 0.0, 16002, 1, 1, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 106001, "クランに入れるらしいわよ\nせっかくだから入ってみたら？\nけっこう楽しいみたいよ♪", 0, 16, "キャル", -363.0, 0, 0.0, 16003, 1, 1, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 105901, "こちらでクランに加入できます\n素敵なクランがたくさんあって、\n目移りしてしまいますね", 0, 16, "コッコロ", -363.0, 0, 0.0, 16004, 1, 1, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 105901, " こちらではクランバトルに\n 参加された仲間のみなさんの\n 活躍を振り返ることができます", 0, 17, "コッコロ", -363.0, 0, 0.0, 17002, 1, 1, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 106001, "模擬戦の戦績もアンタが\n気に入ったものがあれば\n記録しておけるのね", 0, 25, "キャル", -363.0, 0, 0.0, 17004, 1, 1, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 105901, "主さま、今回のクランバトルでの\nご活躍が記録されています\nバトルの参考にいたしましょう", 0, 25, "コッコロ", -363.0, 0, 0.0, 17005, 1, 1, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 106401, "今回のクランバトルの調子は\nどうかしら？\n戦績を見れば、次のバトルに\n活かせるかもしれないわ", 0, 25, "シェフィ", -363.0, 2104010, 0.0, 17006, 1, 1, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 2);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 105801, "今回のクランバトルでの戦績を\nおさらいできますよ！\n私にも見せてください☆", 0, 25, "ペコリーヌ", -363.0, 0, 0.0, 17007, 1, 1, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 190801, "ようこそ！\nこちらでは、\nギルドハウスで流れる音楽の\n変更や購入が出来ますよ", 0, 18, "カリン", -363.0, 0, 0.0, 18001, 1, 1, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 190801, "ＢＧＭの変更や購入は、こちらから\nできますよ\n素敵な音楽を、たくさんご用意\nいたしました！", 0, 18, "カリン", -363.0, 0, 0.0, 18002, 2, 1, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 190801, "ギルドハウスの\nＢＧＭを変更できますよ\nあなたの好きな曲、\n私にも聴かせてくださいね", 0, 19, "カリン", -470.0, 0, 0.0, 19001, 3, 1, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 190801, "こちらでは、ＢＧＭの変更が\nできますよ\nどんな曲に変更しますか？\nふふふ、私も楽しみです♪", 0, 19, "カリン", -470.0, 0, 0.0, 19002, 4, 1, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 190801, "こちらでは、ＢＧＭを購入\nすることができますよ\n試聴することもできるので、\nじっくり選んでくださいね", 0, 20, "カリン", -470.0, 0, 0.0, 20001, 5, 1, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 190801, "いらっしゃいませ！\nＢＧＭの購入はこちらです\n素敵な曲がたくさんあって、\n目移りしちゃいますね", 0, 20, "カリン", -470.0, 0, 0.0, 20002, 6, 1, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 106001, "ここで手に入れたアイテムで\n専用装備を作成できるみたいね\nアイテムが集まったら\nさっそく作ってみましょ！", 0, 21, "キャル", -363.0, 0, 0.0, 21001, 1, 1, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 105901, "攻略すると珍しいアイテムが\n手に入りますよ\nこのアイテムで専用装備を\n作成できるようです", 0, 21, "コッコロ", -363.0, 0, 0.0, 21002, 1, 1, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 106401, "専用装備が欲しいなら\nこのクエストに挑戦するといいわ\n集めた素材でもっともっと\n強くなりましょう", 0, 21, "シェフィ", -363.0, 2104010, 0.0, 21003, 1, 1, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 2);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 105801, "専用装備の作成に必要な\nアイテムを獲得できますよ\nたくさん集めてどんどん\n強くなりましょう！", 0, 21, "ペコリーヌ", -363.0, 0, 0.0, 21004, 1, 1, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 190801, "投票はこちらです\nあなたが応援したい女の子に\n思いを込めた一票を\nお願いします！", 0, 22, "カリン", -430.0, 0, 0.0, 22001, 1, 1, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 190801, "ようこそ！\nあなたが思いを寄せるのは\nどの女の子ですか？\n応援してあげてくださいね！", 0, 22, "カリン", -430.0, 0, 0.0, 22002, 2, 1, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 190801, "たくさんの投票、\nありがとうございました\n結果発表を楽しみに\n待っていてくださいね！", 0, 23, "カリン", -430.0, 0, 0.0, 23001, 3, 1, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 190801, "ただ今、人気投票の\n集計中です\n結果が出るまでもう少しだけ\nお待ちくださいね", 0, 23, "カリン", -430.0, 0, 0.0, 23002, 4, 1, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (8.0, 109001, "あなた様が手伝ってくださった\nチョコレートケーキ\n美味しくないはずがありませんわ", 10011, 24, "エリコ（バレンタイン）", -385.0, 0, 4.08, 24001, 1, 2, "2030/12/17 14:59:59", "2019/01/31 12:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (8.0, 109001, "このような失敗、あなた様が\nするはずありません\nもう一度挑戦してみましょう", 10011, 24, "エリコ（バレンタイン）", -385.0, 0, 5.0, 24002, 2, 2, "2030/12/17 14:59:59", "2019/01/31 12:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (8.0, 109001, "あなた様のために\n作っているケーキを\nあなた様に手伝っていただく……\nことになるなんて……クスクス", 10011, 24, "エリコ（バレンタイン）", -385.0, 0, 10.11, 24003, 3, 2, "2030/12/17 14:59:59", "2019/01/31 12:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (8.0, 109001, "あまり気に病む必要はありませんわ\nこれからは私がたっぷりと\n時間をかけて教えて差し上げますから", 10011, 24, "エリコ（バレンタイン）", -385.0, 0, 4.0, 24004, 4, 2, "2030/12/17 14:59:59", "2019/01/31 12:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (8.0, 109001, "今回は調子が悪かった……のですか？\nあなた様が手伝ってくれたものなら\nわたしはどんなものでも……クスクス", 10011, 24, "エリコ（バレンタイン）", -385.0, 0, 6.0, 24005, 5, 2, "2030/12/17 14:59:59", "2019/01/31 12:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 109002, "あなた様が手がけた\nチョコレートケーキは\n私にとっての宝物……\n侮辱する者は生かしておきませんわ", 10011, 24, "エリコ（バレンタイン）", 0.0, 0, 0.0, 24006, 6, 1, "2030/12/17 14:59:59", "2019/01/31 12:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 109002, "とても素晴らしい出来栄えですわ！\nあなた様にふさわしい\nチョコレートケーキができました", 10011, 24, "エリコ（バレンタイン）", 0.0, 0, 0.0, 24007, 7, 1, "2030/12/17 14:59:59", "2019/01/31 12:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 109002, "私を手伝ってくれたあなた様は\nすでに私の虜……\n甘い世界に誘って差し上げますわ", 10011, 24, "エリコ（バレンタイン）", 0.0, 0, 0.0, 24008, 8, 1, "2030/12/17 14:59:59", "2019/01/31 12:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 109002, "あなた様の愛情\nしかと受け止めました\nこれが……私たちの初めての\n共同作業ですわね……クスクス", 10011, 24, "エリコ（バレンタイン）", 0.0, 0, 0.0, 24009, 9, 1, "2030/12/17 14:59:59", "2019/01/31 12:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 109002, "これは世界一の\nチョコレートケーキですわ\nだって、あなた様が腕によりをかけて\n作ってくださったんですもの", 10011, 24, "エリコ（バレンタイン）", 0.0, 0, 0.0, 24010, 10, 1, "2030/12/17 14:59:59", "2019/01/31 12:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (8.0, 109101, "上手にできなくて残念だった？\nでも、弟くんの気持ちが嬉しいな\nいつだってお姉ちゃんは\nそばにいるからね♪", 10011, 24, "シズル（バレンタイン）", -385.0, 0, 2.12, 24011, 1, 2, "2030/12/17 14:59:59", "2019/01/31 12:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (8.0, 109101, "うーん、弟くんには珍しく\n緊張しちゃったのかな？\nもう一度チャレンジしてみる？", 10011, 24, "シズル（バレンタイン）", -385.0, 0, 4.19, 24012, 2, 2, "2030/12/17 14:59:59", "2019/01/31 12:00:00", 5);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (8.0, 109101, "お姉ちゃんのお手伝い、\nよくできました！\nあー、\nまだつまみ食いしちゃダメだぞ！", 10011, 24, "シズル（バレンタイン）", -385.0, 0, 2.3, 24013, 3, 4, "2030/12/17 14:59:59", "2019/01/31 12:00:00", 2);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 109102, "見てみて！\nスポンジに綺麗な焼き目がついてるよ\nさっすが弟くんだね！", 10011, 24, "シズル（バレンタイン）", 0.0, 0, 0.0, 24014, 4, 1, "2030/12/17 14:59:59", "2019/01/31 12:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (8.0, 109101, "まぁまぁ、落ち込まないで\n見た目は……個性的だけど、\n味は絶対美味しいはずだから！", 10011, 24, "シズル（バレンタイン）", -385.0, 0, 5.23, 24015, 5, 2, "2030/12/17 14:59:59", "2019/01/31 12:00:00", 5);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 109102, "弟くんみたいな\n可愛いケーキができたよ！\n早く食べてみたいでしょ♪", 10011, 24, "シズル（バレンタイン）", 0.0, 0, 0.0, 24016, 6, 1, "2030/12/17 14:59:59", "2019/01/31 12:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (8.0, 109101, "あれれ？　弟くん、指に\nチョコレートがくっついてるよ？\nお姉ちゃんが舐めてあげるね、\nはぁむ！", 10011, 24, "シズル（バレンタイン）", -385.0, 0, 5.01, 24017, 7, 2, "2030/12/17 14:59:59", "2019/01/31 12:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 109102, "なかなか上手にできたんじゃない？\nでも弟くんはまだまだできる子！\nお姉ちゃん、信じてるからね", 10011, 24, "シズル（バレンタイン）", 0.0, 0, 0.0, 24018, 8, 1, "2030/12/17 14:59:59", "2019/01/31 12:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 109102, "わぁ～、\nとっても美味しそうにできたね！\n弟くん手慣れてたから\nお姉ちゃん安心して任せられちゃった！", 10011, 24, "シズル（バレンタイン）", 0.0, 0, 0.0, 24019, 9, 1, "2030/12/17 14:59:59", "2019/01/31 12:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 109102, "や～ん、弟くんが手伝ってくれた\nチョコレートケーキ！\nすっごく美味しそうにできたね♪", 10011, 24, "シズル（バレンタイン）", 0.0, 0, 0.0, 24020, 10, 1, "2030/12/17 14:59:59", "2019/01/31 12:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 106401, "ここから先は神聖な場所みたい\nどんなお宝が眠っているのか、\n今から探索するのが楽しみね♪", 0, 26, "シェフィ", -363.0, 2104010, 0.0, 26001, 1, 1, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 2);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 105801, "ここから先は神聖な場所\nみたいです！\nどんなお宝が手に入るか\n楽しみですね！", 0, 26, "ペコリーヌ", -363.0, 0, 0.0, 26002, 1, 1, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 106001, "この先は神聖な場所みたい。\n手に入るお宝も並じゃないけど\n気を付けていかないと\n痛い目にあうわよ", 0, 26, "キャル", -363.0, 0, 0.0, 26003, 1, 1, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 105901, "ここから先は神聖な場所\nでございます。\n気を引き締めてお宝の\n調査探索に参りましょう", 0, 26, "コッコロ", -363.0, 0, 0.0, 26004, 1, 1, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 106401, "ここにさらなる力を得るための\nアイテムが眠っている…って\nみんな言ってるわ。ふふっ、\nそれじゃあ挑戦してみましょうか", 0, 27, "シェフィ", -363.0, 2104010, 0.0, 27001, 1, 1, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 2);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 105801, "ここにさらなる力を得るための\nアイテムが眠っているみたい\nです！　どこから挑戦するか\n迷っちゃいますね！", 0, 27, "ペコリーヌ", -363.0, 0, 0.0, 27002, 1, 1, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 106001, "ここにさらなる力を得るための\nアイテムが眠っているみたい！\nどんどん挑戦して\n強くなっちゃいましょ！", 0, 27, "キャル", -363.0, 0, 0.0, 27003, 1, 1, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 105901, "こちらにさらなる力を得る\nためのアイテムが眠っている\nようです。主さま、どこから\n挑戦いたしましょう。", 0, 27, "コッコロ", -363.0, 0, 0.0, 27004, 1, 1, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 190801, "ようこそ！\n皆さんの素敵な出会いを\nギルド管理協会が\nお手伝いします！", 0, 28, "カリン", -363.0, 0, 0.0, 28001, 1, 1, "2030/12/17 14:59:59", "2019/09/24 15:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 190801, "ギルド管理協会です\nフレンドに関しては\nこちらでご確認ください", 0, 28, "カリン", -363.0, 0, 0.0, 28002, 2, 1, "2030/12/17 14:59:59", "2019/09/24 15:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 190801, "こちらがフレンドの\n皆さんです\n素敵な関係を\n築いてくださいね！", 0, 29, "カリン", -409.0, 0, 0.0, 29001, 3, 1, "2030/12/17 14:59:59", "2019/09/24 15:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 190801, "こちらの一覧で\nフレンドのプロフィールを\n確認できますよ", 0, 29, "カリン", -409.0, 0, 0.0, 29002, 4, 1, "2030/12/17 14:59:59", "2019/09/24 15:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 190801, "フレンド管理は\nこちらになります\n新しいフレンドとの出会いを\n楽しんでくださいね！", 0, 30, "カリン", -409.0, 0, 0.0, 30001, 5, 1, "2030/12/17 14:59:59", "2019/09/24 15:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 190801, "フレンドの申請や\n承認ができますよ\nどうぞ、良き交流を！", 0, 30, "カリン", -409.0, 0, 0.0, 30002, 6, 1, "2030/12/17 14:59:59", "2019/09/24 15:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 190801, "バトルをして力比べを\nしてみましょう！\n実力が試されますね、\n頑張ってください！", 0, 31, "カリン", -409.0, 0, 0.0, 31001, 7, 1, "2030/12/17 14:59:59", "2019/10/31 12:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 190801, "気になるパーティと\nバトルをしてみましょう！\nどちらが勝利するのか、\n私も楽しみにしていますね", 0, 31, "カリン", -409.0, 0, 0.0, 31002, 8, 1, "2030/12/17 14:59:59", "2019/10/31 12:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 190801, "ルーキーの皆さんのために\n特別なミッションを\nご用意いたしました！\nぜひ、挑戦してください！", 0, 32, "カリン", -409.0, 0, 0.0, 32001, 1, 1, "2020/01/04 4:59:59", "2019/12/20 5:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 190801, "期間限定のキャンペーンを\n開催中です！\nミッションにチャレンジ\nしましょう！", 0, 32, "カリン", -409.0, 0, 0.0, 32002, 2, 1, "2020/01/04 4:59:59", "2019/12/20 5:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 190801, "フレンドになって\n初心者の方を応援しましょう！\n素敵な報酬が待っていますよ！", 0, 33, "カリン", -409.0, 0, 0.0, 33001, 3, 1, "2020/01/04 4:59:59", "2019/12/20 5:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 190801, "期間限定のキャンペーンを\n開催中です！\nミッションにチャレンジ\nしましょう！", 0, 33, "カリン", -409.0, 0, 0.0, 33002, 4, 1, "2020/01/04 4:59:59", "2019/12/20 5:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 190801, "お疲れ様でした！\nミッションの報酬の受け取りは\nこちらからできますよ！", 0, 34, "カリン", -409.0, 0, 0.0, 34001, 5, 1, "2020/01/10 11:59:59", "2020/01/04 5:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 190801, "ミッション報酬の受け取りは\nこちら！\n受け取り漏れの無いように\n気を付けてくださいね！", 0, 34, "カリン", -409.0, 0, 0.0, 34002, 6, 1, "2020/01/10 11:59:59", "2020/01/04 5:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 105801, "過去のストーリーイベントを\n楽しめちゃいますよ！\n遊んだことのないものがあれば\n一緒にやってみましょう♪", 0, 38, "ペコリーヌ", -458.0, 0, 5.3, 38001, 1, 2, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 105801, "これまでのイベントで登場した\n限定キャラを仲間にできたり\nメモリーピースが手に入る\nみたいですよ。やばいですね☆", 0, 38, "ペコリーヌ", -458.0, 0, 6.5, 38002, 2, 2, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (9999.0, 105801, "", 0, 39, "ペコリーヌ", 9999.0, 0, 0.0, 39005, 0, 3, "2020/04/08 23:59:59", "2020/04/01", 3);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 190801, "これまでに出題された\n問題を振り返ることが\nできますよ\n復習は大切です♪", 0, 40, "カリン", -430.0, 0, 0.0, 40001, 2, 1, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 106401, "ここでは腕試しが\nできるんですって。\n自分の実力を測るのに、\nちょうどよさそうね。", 0, 41, "シェフィ", -363.0, 2104010, 0.0, 41001, 1, 1, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 105801, "ここで腕試しを\nしていきましょう！\n全力全開、\nがんばっちゃいますよ～！", 0, 41, "ペコリーヌ", -363.0, 0, 0.0, 41002, 1, 1, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 106001, "ここで腕試しが\nできるみたいね。\n試してみるのも\nいいんじゃない？", 0, 41, "キャル", -363.0, 0, 0.0, 41003, 1, 1, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 105901, "腕試しができるようです。\nここで練習を重ね、実戦に\n活かしてまいりましょう。", 0, 41, "コッコロ", -363.0, 0, 0.0, 41004, 1, 1, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 105901, "訓練の成果に応じて、\n報酬がもらえるそうです。\n共に励んでいきましょう。", 0, 42, "コッコロ", -416.5, 0, 0.0, 42001, 1, 1, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 106401, "目標を達成すれば、\n報酬がもらえるみたい。\n頑張り甲斐があるわね。", 0, 42, "シェフィ", -416.5, 2104010, 0.0, 42002, 1, 1, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 105801, "腕試しをがんばれば、\n報酬がもらえますよ。\n挑戦していきましょう☆", 0, 42, "ペコリーヌ", -416.5, 0, 0.0, 42003, 1, 1, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 106001, "ミッションを達成すると、\n報酬が出るんですって。\n一緒にやってみましょ！", 0, 42, "キャル", -416.5, 0, 0.0, 42004, 1, 1, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 105801, "ここからアリーナに\n挑戦できますよ！\n編成を工夫してライバルに\n挑んじゃいましょう！", 0, 43, "ペコリーヌ", -363.0, 0, 0.0, 43001, 1, 1, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 105901, "こちらからアリーナに\n挑戦することができます。\n主さまらしい編成で\nライバルに挑みましょう。", 0, 43, "コッコロ", -363.0, 0, 0.0, 43002, 1, 1, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 106001, "ここからアリーナに\n挑戦できるわよ！\nしっかり編成を考えて\nライバルに挑みなさい！", 0, 43, "キャル", -363.0, 0, 0.0, 43003, 1, 1, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 123001, "ミッションをクリアすると報酬が\n受け取れるわ。ジャンジャン\nクリアしてバリバリ強化して\nあげなさい♪", 0, 44, "アメス", -416.5, 0, 0.0, 43004, 1, 1, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 123001, "ぼんやりしてる場合じゃないわ。\n早くミッションをクリアして\n報酬を受け取ってきなさい！", 0, 44, "アメス", -416.5, 0, 0.0, 43005, 2, 1, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 123001, "ちょっとあんた、報酬が\n受け取れるじゃない！\n忘れずにチェックなさい。\nアメス様との約束よ？", 0, 45, "アメス", -416.5, 0, 5.79, 43006, 3, 2, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 123001, "はい、お疲れさま。\nここではマスタリーチケットを\n使って、マスタリー強化素材を\n手に入れることができるわよ。", 0, 46, "アメス", -371.5, 0, 0.0, 46001, 1, 1, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 104901, "呼ばれて飛び出てお姉ちゃんだよ♪\nたとえ火の中、水の中、迷宮の中っ\nこのダンジョンを踏破できるよう\n弟くんを応援してあげるからねっ♪", 0, 47, "シズル", -416.5, 0, 0.0, 47001, 1, 2, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 2);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 101101, "ほんとーに不思議な場所ですね～\nお兄ちゃんが冒険を頑張れるよう\nおまじないをかけてあげますねっ\nフレーフレー、お・兄・ちゃんっ♪", 0, 47, "リノ", -416.5, 0, 9.32, 47002, 1, 2, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0.0, 104901, "", 0, 48, "シズル", -470.0, 0, 0.0, 48001, 0, 2, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 2);
